import requests
import json

# 获取链接数据
links_data = json.loads(inputs.get('links', '{}'))
links = links_data.get('links', [])

# 抓取网页内容
results = []
for link in links:
    try:
        response = requests.get(link['url'], timeout=5)
        if response.status_code == 200:
            results.append({
                'title': link['title'],
                'url': link['url'],
                'content': response.text[:1000],  # 限制内容长度
                'priority': link['priority']
            })
    except Exception as e:
        print(f"抓取失败 {link['url']}: {e}")

outputs = {'scraped_results': json.dumps(results)}

